mapper.select:
select va.id, va.user_id, va.name, va.phone, va.appointment_time, va.additional_info, va.appointment_status, va.guide_type, va.guide_id, ai.name apartment_name, ri.room_number, gi.name, gi.url from view_appointment va left join room_info ri on va.room_id = ri.id and ri.is_deleted = 0 left join apartment_info ai on va.apartment_id = ai.id and ai.is_deleted = 0 left join graph_info gi on gi.item_type = 1 and gi.item_id = ai.id and gi.is_deleted = 0 where va.is_deleted = 0 and ri.publisher_id = #{landlordId} and ri.publisher_type = 2 and va.guide_type = 2 -- 只显示选择房东带看的预约 and va.guide_id = #{landlordId} -- 确保带看人就是该房东
and va.appointment_status = #{status}
order by va.appointment_time desc

select va.id, va.user_id, va.name, va.phone, va.appointment_time, va.additional_info, va.appointment_status, va.guide_type, va.guide_id, ai.name apartment_name, ri.room_number, gi.name, gi.url from view_appointment va left join room_info ri on va.room_id = ri.id and ri.is_deleted = 0 left join apartment_info ai on va.apartment_id = ai.id and ai.is_deleted = 0 left join graph_info gi on gi.item_type = 1 and gi.item_id = ai.id and gi.is_deleted = 0 where va.is_deleted = 0 and ri.publisher_id = #{landlordId} and ri.publisher_type = 2 and va.guide_type = 2 -- 只显示选择房东带看的预约 and va.guide_id = #{landlordId} -- 确保带看人就是该房东
and va.appointment_status = #{status}
order by va.appointment_time desc
